final:
module RefModule(
    input clk,
    input rst,
    input load,
    input [15:0] d,

    output reg [15:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt)
begin
  if(rst)
  begin
    q <= 16'b0;
  end
  else if(load)
  begin
    q <= d;
  end
end

endmodule
